<?php/DevelopmentErrorReportingif(!defined('DEVELOPMENT_MODE')){error_reporting(E_ALL);ini_set('display_errors',1);ini_set('display_startup_errors',1);}declare(strict_types=1);/***NRPFormatFixer*CorrectinvalidNRPformatsinpersoniltable*/require_once__DIR__.'/../core/config.php';require_once__DIR__.'/../core/Database.php';require_once__DIR__.'/APIResponse.php';classNRPFormatFixer{private$pdo;publicfunction__construct(){$db=Database::getInstance();$this->pdo=$db->getConnection();}/***FixallinvalidNRPformats*/publicfunctionfixInvalidNRP(){$results=[];try{/GetallinvalidNRPrecords$invalid_nrps=$this->getInvalidNRP();if(empty($invalid_nrps)){return['success'=>true,'message'=>'NoinvalidNRPformatsfound','fixed_count'=>0,'timestamp'=>date('c')];}$fixed_count=0;forforeach($invalid_nrpsas$invalid_nrp){$fix_result=$this->fixSingleNRP($invalid_nrp);$results[]=$fix_result;if($fix_result['status']==='fixed'){$fixed_count++;}}return['success'=>true,'message'=>"Fixed{$fixed_count}invalidNRPformats",'results'=>$results,'fixed_count'=>$fixed_count,'total_invalid'=>count($invalid_nrps),'timestamp'=>date('c')];}catch(Exception$e){return['success'=>false,'message'=>'ErrorfixingNRPformats:'.$e->getMessage(),'timestamp'=>date('c')];}}/***GetallinvalidNRPrecords*/privatefunctiongetInvalidNRP(){$sql="SELECTid,nama,nrpFROMpersonilWHEREis_deleted=0ANDnrpISNOTnullANDnrp!=''ANDnrpNOTREGEXP'^[0-9]{8,9}$'ORDERBYid";$stmt=$this->pdo->query($sql);return$stmt->fetchAll(PDO::FETCH_ASSOC);}/***FixsingleNRPrecord*/privatefunctionfixSingleNRP($personil){$id=$personil['id'];$nama=$personil['nama'];$current_nrp=$personil['nrp'];/TrytofixNRPformat$fixed_nrp=$this->normalizeNRP($current_nrp);if($fixed_nrp===$current_nrp){return['id'=>$id,'nama'=>$nama,'current_nrp'=>$current_nrp,'status'=>'unchanged','message'=>'NRPformatalreadycorrectorcannotbefixedautomatically'];}/CheckiffixedNRPalreadyexistsif($this->nrpExists($fixed_nrp,$id)){return['id'=>$id,'nama'=>$nama,'current_nrp'=>$current_nrp,'proposed_nrp'=>$fixed_nrp,'status'=>'conflict','message'=>'FixedNRPconflictswithexistingrecord'];}/Updatetherecordtry{$update_sql="UPDATEpersonilSETnrp=?,updated_at=NOW()WHEREid=?";$stmt=$this->pdo->prepare($update_sql);$result=$stmt->execute([$fixed_nrp,$id]);if($result){return['id'=>$id,'nama'=>$nama,'old_nrp'=>$current_nrp,'new_nrp'=>$fixed_nrp,'status'=>'fixed','message'=>'NRPformatcorrectedsuccessfully'];}else{return['id'=>$id,'nama'=>$nama,'current_nrp'=>$current_nrp,'status'=>'error','message'=>'FailedtoupdateNRP'];}}catch(Exception$e){return['id'=>$id,'nama'=>$nama,'current_nrp'=>$current_nrp,'status'=>'error','message'=>'Databaseerror:'.$e->getMessage()];}}/***NormalizeNRPformat*/privatefunctionnormalizeNRP($nrp){/Removeallnon-digitcharacters$digits_only=preg_replace('/[^0-9]/','',$nrp);/Ifemptyaftercleaning,returnoriginalif(empty($digits_only)){return$nrp;}/Iftooshortortoolong,returnoriginalif(strlen($digits_only)<6||strlen($digits_only)>10){return$nrp;}/Padwithleadingzerosifneededtomake8digitsif(strlen($digits_only)<8){$digits_only=str_pad($digits_only,8,'0',STR_PAD_LEFT);}/Ifmorethan8digits,truncateto8(forcaseslike9digits)if(strlen($digits_only)>8){$digits_only=substr($digits_only,0,8);}return$digits_only;}/***CheckifNRPalreadyexists(excludingcurrentrecord)*/privatefunctionnrpExists($nrp,$exclude_id){$sql="SELECTCOUNT(*)ascountFROMpersonilWHEREnrp=?ANDid!=?ANDis_deleted=0";$stmt=$this->pdo->prepare($sql);$stmt->execute([$nrp,$exclude_id]);return$stmt->fetch()['count']>0;}/***VerifyNRPformatconsistencyafterfix*/publicfunctionverifyNRPFormats(){$sql="SELECTCOUNT(*)astotal_invalidFROMpersonilWHEREis_deleted=0ANDnrpISNOTnullANDnrp!=''ANDnrpNOTREGEXP'^[0-9]{8,9}$'";$stmt=$this->pdo->query($sql);$total_invalid=$stmt->fetch()['total_invalid'];/Getformatstatistics$stats_sql="SELECTCASEWHENnrpREGEXP'^[0-9]{8,9}$'THEN'valid'WHENnrpISnullORnrp=''THEN'empty'ELSE'invalid'ENDasformat_status,COUNT(*)ascountFROMpersonilWHEREis_deleted=0GROUPBYformat_statusORDERBYformat_status";$stmt=$this->pdo->query($stats_sql);$format_stats=$stmt->fetchAll(PDO::FETCH_ASSOC);return['success'=>$total_invalid===0,'total_invalid'=>(int)$total_invalid,'format_statistics'=>$format_stats,'all_valid'=>$total_invalid===0,'timestamp'=>date('c')];}/***GetdetailedNRPanalysis*/publicfunctiongetNRPAnalysis(){$analysis=[];/GetallNRPpatterns$pattern_sql="SELECTnrp,CASEWHENnrpREGEXP'^[0-9]{8,9}$'THEN'valid'WHENnrpISnullORnrp=''THEN'empty'ELSE'invalid'ENDasformat_status,LENGTH(nrp)aslength,nrpREGEXP'^[0-9]+$'asdigits_onlyFROMpersonilWHEREis_deleted=0ORDERBYidLIMIT20";$stmt=$this->pdo->query($pattern_sql);$analysis['samples']=$stmt->fetchAll(PDO::FETCH_ASSOC);/Getsummarystatistics$summary_sql="SELECTCOUNT(*)astotal,COUNT(CASEWHENnrpREGEXP'^[0-9]{8,9}$'THEN1END)asvalid,COUNT(CASEWHENnrpISnullORnrp=''THEN1END)asempty,COUNT(CASEWHENnrpNOTREGEXP'^[0-9]{8,9}$'ANDnrpISNOTnullANDnrp!=''THEN1END)asinvalidFROMpersonilWHEREis_deleted=0";$stmt=$this->pdo->query($summary_sql);$analysis['summary']=$stmt->fetch(PDO::FETCH_ASSOC);return$analysis;}}/Executeifaccesseddirectlyif(basename($_SERVER['PHP_SELF'])===basename(__FILE__)){header('Content-Type:application/json');try{$fixer=newNRPFormatFixer();/Getanalysisbeforefix$analysis=$fixer->getNRPAnalysis();/FixinvalidNRP$fix_result=$fixer->fixInvalidNRP();/Verifyafterfix$verify_result=$fixer->verifyNRPFormats();echojson_encode(APIResponse::success(['analysis'=>$analysis,'fix_result'=>$fix_result,'verification'=>$verify_result],'NRPformatfixcompleted'));}catch(Exception$e){echojson_encode(APIResponse::error($e->getMessage(),500));}}?>
